from sqlalchemy.orm import sessionmaker, declarative_base

DATABASE_URL = "sqlite:///./app.db"
engine = create_engine(DATABASE_URL, connect_args={"check_same_thread": False})
SessionLocal = sessionmaker(bind=engine, autoflush=False, autocommit=False)
Base = declarative_base()


class Item(Base):
    __tablename__ = "items"
    id = Column(Integer, primary_key=True)
    name = Column(String, unique=True, nullable=False)
    price = Column(Float, nullable=False)
    created_at = Column(DateTime, default=lambda: datetime.now(timezone.utc), nullable=False)


class ItemCreate(BaseModel):
    name: str
    price: float


class ItemOut(BaseModel):
    id: int
    name: str
    price: float
    created_at: datetime

    class Config:
        from_attributes = True


app = FastAPI()
buckets = defaultdict(lambda: deque())
RATE_LIMIT = 10
WINDOW_SECONDS = 60


@app.middleware("http")
async def rate_limit(request: Request, call_next):
    ip = request.client.host if request.client else "unknown"
    now = datetime.now(timezone.utc).timestamp()
    window = buckets[ip]
    while window and now - window[0] > WINDOW_SECONDS:
        window.popleft()
    if len(window) >= RATE_LIMIT:
        return _JSON_429()
    window.append(now)
    return await call_next(request)


def _JSON_429():
    from fastapi.responses import JSONResponse
    return JSONResponse(status_code=429, content={"error": "rate_limited"})


def get_db():
    db = SessionLocal()
    try:
        yield db
    finally:
        db.close()


@app.on_event("startup")
def on_startup():
    Base.metadata.create_all(bind=engine)


@app.post("/items", response_model=ItemOut, status_code=201)
def create_item(payload: ItemCreate, db=Depends(get_db)):
    existing = db.query(Item).filter(Item.name == payload.name).first()
    if existing:
        raise HTTPException(status_code=409, detail="duplicate_name")
    item = Item(name=payload.name, price=payload.price)
    db.add(item)
    db.commit()
    db.refresh(item)
    return item


@app.get("/items", response_model=list[ItemOut])
def list_items(db=Depends(get_db)):
    return db.query(Item).all()


@app.get("/items/{item_id}", response_model=ItemOut)
def get_item(item_id: int, db=Depends(get_db)):
    item = db.get(Item, item_id)
    if not item:
        raise HTTPException(status_code=404, detail="not_found")
    return item


@app.delete("/items/{item_id}", status_code=204)
def delete_item(item_id: int, db=Depends(get_db)):
    item = db.get(Item, item_id)
    if not item:
        raise HTTPException(status_code=404, detail="not_found")
    db.delete(item)
    db.commit()
    return None

import asyncio
import httpx


async def fetch_with_retry(url, max_retries=3, base_delay=0.5):
    last_exc = None
    async with httpx.AsyncClient(timeout=10.0) as client:
        for attempt in range(max_retries):
            try:
                response = await client.get(url)
                if response.status_code < 500:
                    return response.json()
                last_exc = httpx.HTTPStatusError(
                    f"Server error {response.status_code}",
                    request=response.request,
                    response=response,
                )
            except (httpx.RequestError, httpx.HTTPStatusError) as exc:
                last_exc = exc
            await asyncio.sleep(base_delay * (2 ** attempt))
    raise last_exc

def quicksort(arr):
    if len(arr) <= 1:
        return list(arr)
    mid = len(arr) // 2
    pivot = arr[mid]
    left = [x for i, x in enumerate(arr) if i != mid and x < pivot]
    right = [x for i, x in enumerate(arr) if i != mid and x >= pivot]
    return quicksort(left) + [pivot] + quicksort(right)

