import hashlib
import os
import sys
from collections import defaultdict

CHUNK = 64 * 1024

def md5_of(path):
    h = hashlib.md5()
    with open(path, "rb") as f:
        while True:
            data = f.read(CHUNK)
            if not data:
                break
            h.update(data)
    return h.hexdigest()

def find_duplicates(root):
    size_map = defaultdict(list)
    for dirpath, _, filenames in os.walk(root):
        for name in filenames:
            full = os.path.join(dirpath, name)
            try:
                size_map[os.path.getsize(full)].append(full)
            except OSError:
                continue

    hash_map = defaultdict(list)
    for size, files in size_map.items():
        if len(files) < 2:
            continue
        for f in files:
            try:
                hash_map[md5_of(f)].append(f)
            except OSError:
                continue

    dups = {h: paths for h, paths in hash_map.items() if len(paths) > 1}
    return dups

def main():
    if len(sys.argv) != 2:
        print("Usage: python dupfinder.py <directory>", file=sys.stderr)
        sys.exit(1)
    groups = find_duplicates(sys.argv[1])
    if not groups:
        print("No duplicates found.")
        return
    for i, (_, paths) in enumerate(groups.items(), 1):
        print(f"--- Duplicate group {i} ---")
        for p in paths:
            print(p)

if __name__ == "__main__":
    main()

import functools
import timeit

@functools.lru_cache(maxsize=None)
def fib_recursive(n):
    if n < 2:
        return n
    return fib_recursive(n - 1) + fib_recursive(n - 2)

def fib_iterative(n):
    if n < 0:
        raise ValueError("n must be non-negative")
    a, b = 0, 1
    for _ in range(n):
        a, b = b, a + b
    return a

def benchmark(fn, n, runs=5):
    times = timeit.repeat(lambda: fn(n), number=1, repeat=runs)
    return min(times)

if __name__ == "__main__":
    N = 200
    t_rec = benchmark(fib_recursive, N)
    t_it  = benchmark(fib_iterative, N)
    print(f"fib({N}) recursive = {fib_recursive(N)} in {t_rec:.6f}s")
    print(f"fib({N}) iterative = {fib_iterative(N)} in {t_it:.6f}s")
    print(f"speedup: {t_rec / t_it:.1f}x")

def merge_sorted_lists(a, b):
    result = []
    i = j = 0
    while i < len(a) and j < len(b):
        if a[i] <= b[j]:
            result.append(a[i])
            i += 1
        else:
            result.append(b[j])
            j += 1
    result.extend(a[i:])
    result.extend(b[j:])
    return result

