import threading

class SafeCounter:
    def __init__(self):
        self._value = 0
        self._lock = threading.Lock()

    def increment(self):
        with self._lock:
            self._value += 1

    def decrement(self):
        with self._lock:
            self._value -= 1

    def get(self):
        with self._lock:
            return self._value

    def reset(self):
        with self._lock:
            self._value = 0

if __name__ == '__main__':
    counter = SafeCounter()
    threads = []
    for _ in range(10):
        t = threading.Thread(target=lambda: [counter.increment() for _ in range(1000)])
        threads.append(t); t.start()
    for t in threads:
        t.join()
    assert counter.get() == 10000, counter.get()
    print('OK:', counter.get())

