import functools, time

def retry(max_attempts=3, delay=0.5, exceptions=(Exception,)):
    def decorator(fn):
        @functools.wraps(fn)
        def wrapper(*args, **kwargs):
            last = None
            for i in range(max_attempts):
                try:
                    return fn(*args, **kwargs)
                except exceptions as e:
                    last = e
                    if i < max_attempts - 1:
                        time.sleep(delay)
            raise last
        return wrapper
    return decorator

