class TrieNode {
    constructor() {
        this.children = {};
        this.isEndOfWord = false;
        this.wordCount = 0; // counts how many words pass through this node (includes repeats)
    }
}

class Trie {
    constructor() {
        this.root = new TrieNode();
    }

    insert(word) {
        let node = this.root;
        for (const char of word) {
            if (!node.children[char]) {
                node.children[char] = new TrieNode();
            }
            node = node.children[char];
            node.wordCount++;
        }
        node.isEndOfWord = true;
    }

    search(word) {
        const node = this._traverse(word);
        return node !== null && node.isEndOfWord;
    }

    startsWith(prefix) {
        return this._traverse(prefix) !== null;
    }

    countWordsWithPrefix(prefix) {
        const node = this._traverse(prefix);
        return node === null ? 0 : node.wordCount;
    }

    delete(word) {
        return this._deleteHelper(this.root, word, 0);
    }

    _deleteHelper(node, word, index) {
        if (index === word.length) {
            if (!node.isEndOfWord) return false;
            node.isEndOfWord = false;
            return Object.keys(node.children).length === 0;
        }

        const char = word[index];
        const child = node.children[char];
        if (!child) return false;

        const shouldDeleteChild = this._deleteHelper(child, word, index + 1);

        if (shouldDeleteChild) {
            delete node.children[char];
            return !node.isEndOfWord && Object.keys(node.children).length === 0;
        }
        return false;
    }

    getAllWordsSorted() {
        const results = [];
        this._collectWords(this.root, '', results);
        return results.sort();
    }

    _collectWords(node, prefix, results) {
        if (node.isEndOfWord) {
            results.push(prefix);
        }
        for (const char of Object.keys(node.children).sort()) {
            this._collectWords(node.children[char], prefix + char, results);
        }
    }

    _traverse(word) {
        let node = this.root;
        for (const char of word) {
            if (!node.children[char]) return null;
            node = node.children[char];
        }
        return node;
    }
}

