const fs = require('fs');
const path = require('path');
const sqlite3 = require('sqlite3').verbose();

const DATA_DIR = path.join(__dirname, 'data');
const DB_PATH = path.join(__dirname, 'records.db');
const REQUIRED = ['id', 'name', 'email'];

const db = new sqlite3.Database(DB_PATH);
db.run(`CREATE TABLE IF NOT EXISTS people (
  id TEXT PRIMARY KEY,
  name TEXT,
  email TEXT
)`);

function parseCSV(content) {
  const lines = content.split(/\r?\n/).filter(l => l.length > 0);
  if (lines.length === 0) return { header: [], rows: [] };
  const header = lines[0].split(',').map(h => h.trim());
  const rows = lines.slice(1).map(l => l.split(',').map(c => c.trim()));
  return { header, rows };
}

function processFile(filepath) {
  fs.readFile(filepath, 'utf8', (err, content) => {
    if (err) {
      console.error(`Error reading ${filepath}: ${err.message}`);
      return;
    }
    const { header, rows } = parseCSV(content);
    const missingCols = REQUIRED.filter(c => !header.includes(c));
    if (missingCols.length > 0) {
      console.warn(`Skipping ${filepath}: missing columns ${missingCols.join(', ')}`);
      return;
    }

    const idIdx = header.indexOf('id');
    const nameIdx = header.indexOf('name');
    const emailIdx = header.indexOf('email');
    let inserted = 0;

    rows.forEach((row, i) => {
      const missing = [];
      if (!row[idIdx]) missing.push('id');
      if (!row[nameIdx]) missing.push('name');
      if (!row[emailIdx]) missing.push('email');
      if (missing.length > 0) {
        console.warn(`  ${path.basename(filepath)} row ${i + 1}: missing ${missing.join(', ')}`);
        return;
      }
      db.run(
        `INSERT OR IGNORE INTO people (id, name, email) VALUES (?, ?, ?)`,
        [row[idIdx], row[nameIdx], row[emailIdx]],
        (e) => { if (!e) inserted++; }
      );
    });

    setTimeout(() => {
      console.log(`Processed ${path.basename(filepath)}: inserted ${inserted}/${rows.length}`);
    }, 50);
  });
}

const watcher = chokidar.watch(path.join(DATA_DIR, '*.csv'), { ignoreInitial: false });
watcher.on('add', processFile);
watcher.on('error', (err) => console.error(`Watcher error: ${err.message}`));
process.on('SIGINT', () => { watcher.close(); db.close(); process.exit(0); });
console.log(`Watching ${DATA_DIR} for new .csv files...`);

