import java.util.HashMap;
import java.util.Map;

public class LRUCache<K, V> {
    private static class Node<K, V> {
        K key;
        V value;
        Node<K, V> prev;
        Node<K, V> next;
        Node(K k, V v) { this.key = k; this.value = v; }
    }

    private final int capacity;
    private final Map<K, Node<K, V>> map;
    private final Node<K, V> head; // dummy head
    private final Node<K, V> tail; // dummy tail

    public LRUCache(int capacity) {
        if (capacity <= 0) throw new IllegalArgumentException("capacity must be > 0");
        this.capacity = capacity;
        this.map = new HashMap<>();
        this.head = new Node<>(null, null);
        this.tail = new Node<>(null, null);
        head.next = tail;
        tail.prev = head;
    }

    public V get(K key) {
        Node<K, V> node = map.get(key);
        if (node == null) return null;
        moveToFront(node);
        return node.value;
    }

    public void put(K key, V value) {
        Node<K, V> existing = map.get(key);
        if (existing != null) {
            existing.value = value;
            moveToFront(existing);
            return;
        }
        if (map.size() >= capacity) {
            Node<K, V> lru = tail.prev;
            removeNode(lru);
            map.remove(lru.key);
        }
        Node<K, V> node = new Node<>(key, value);
        addToFront(node);
        map.put(key, node);
    }

    private void addToFront(Node<K, V> node) {
        node.next = head.next;
        node.prev = head;
        head.next.prev = node;
        head.next = node;
    }

    private void removeNode(Node<K, V> node) {
        node.prev.next = node.next;
        node.next.prev = node.prev;
    }

    private void moveToFront(Node<K, V> node) {
        removeNode(node);
        addToFront(node);
    }

    public int size() { return map.size(); }

    public static void main(String[] args) {
        LRUCache<Integer, String> cache = new LRUCache<>(3);
        cache.put(1, "one");
        cache.put(2, "two");
        cache.put(3, "three");
        System.out.println(cache.get(1)); // prints "one"
        cache.put(4, "four"); // evicts key 2
        System.out.println(cache.get(2)); // prints null
        System.out.println(cache.size()); // prints 3
    }
}

function longestRun(arr, type = 'increasing') {
  if (!Array.isArray(arr) || arr.length === 0) return 0;
  if (!['increasing', 'decreasing', 'either'].includes(type)) {
    throw new Error("type must be 'increasing', 'decreasing', or 'either'");
  }

  let maxLen = 1;
  let currentLen = 1;

  for (let i = 1; i < arr.length; i++) {
    const diff = arr[i] - arr[i - 1];
    let match = false;
    if (type === 'increasing') match = diff === 1;
    else if (type === 'decreasing') match = diff === -1;
    else match = diff === 1 || diff === -1;

    if (match) {
      currentLen++;
      if (currentLen > maxLen) maxLen = currentLen;
    } else {
      currentLen = 1;
    }
  }
  return maxLen;
}

// Demos
console.log(longestRun([1,2,3,5,6,7,8,10]));             // 4 (5..8)
console.log(longestRun([5,4,3,2,1]));                    // 5 (decreasing)
console.log(longestRun([1,2,3,5,4,3,2], 'decreasing'));  // 4 (5..2)
console.log(longestRun([1,3,5,6,7,9], 'either'));        // 3 (5,6,7)
